mapper.select:
select
from client_channel cc left join client_business cb on cc.client_id = cb.id and cb.is_delete = 0 left join channel c on cc.channel_id = c.id and c.is_delete = 0 where cc.is_delete = 0
order by cc.id desc LIMIT #{offset}, #{limit}

select cc.client_id as clientId, cc.channel_id as channelId, ifnull(cc.client_channel_weight, 0) as clientChannelWeight, cc.client_channel_number as clientChannelNumber, ifnull(cc.is_available, 0) as isAvailable from client_channel cc where cc.is_delete = 0 and cc.client_id in
#{clientId}
order by cc.client_id asc, cc.id asc
